+  /**
+   * Compute network ID from genesis hash
+   */
+  computeNetworkId() {
+    const data = JSON.stringify({
+      version: this.version,
+      name: this.name,
+      type: this.type,
+      creator: this.creator,
+      created: this.created,
+      parameters: this.parameters,
+      nonce: this.nonce,
+    });
